    for p,tgt,head,i in heading_links:
        cand = md_stems.get(tgt,[])
        if cand:
            heads = {m.group(1).strip() for m in re.finditer(r'^#{1,6}\s+(.*)$', cand[0].read_text(encoding='utf-8'), re.M)}
            if head.strip() not in heads: bad.append(f"{rel(p)}:{i} → [[{tgt}#{head}]]")
