            tgt=tgt.strip()
            if tgt and tgt not in known:
                broken.append(f"{rel(p)}:{i}  [[{inner}]]")
            if head: heading_links.append((p,tgt,head,i))
print("  " + ("\n  ".join(broken) if broken else "нет ✓"))

# C. Ссылки на заголовки (#) — проверка существования заголовка
print("\n=== C. Ссылки на #заголовки ===")
if heading_links:
    bad=[]
    for p,tgt,head,i in heading_links:
        cand = md_stems.get(tgt,[])
        if cand:
            heads = {m.group(1).strip() for m in re.finditer(r'^#{1,6}\s+(.*)$', cand[0].read_text(encoding='utf-8'), re.M)}
            if head.strip() not in heads: bad.append(f"{rel(p)}:{i} → [[{tgt}#{head}]]")
    print("  " + ("\n  ".join(bad) if bad else "нет ✓"))
else:
    print("  таких ссылок нет ✓")

# D. Баланс ``` блоков кода
print("\n=== D. Баланс блоков кода (```), callout-типы, frontmatter ===")
fence=[]; fmiss=[]; badcallout=[]
std_callouts={'note','abstract','summary','tldr','info','todo','tip','hint','important',
 'success','check','done','question','help','faq','warning','caution','attention',
 'failure','fail','missing','danger','error','bug','example','quote','cite'}
seen_callouts=set()
for p in mds:
    t=p.read_text(encoding='utf-8')
    if t.count('```')%2: fence.append(rel(p))
    if not t.startswith('---'): fmiss.append(rel(p)+" (нет frontmatter)")
    else:
        if HAVE_YAML:
            try:
                fm=t.split('---',2)[1]; yaml.safe_load(fm)
            except Exception as e: fmiss.append(f"{rel(p)} (YAML: {e})")
    for c in re.findall(r'^>\s*\[!(\w+)\]', t, re.M):
        seen_callouts.add(c.lower())
        if c.lower() not in std_callouts: badcallout.append(f"{rel(p)}: [!{c}]")
print("  Небаланс ``` :", fence or "нет ✓")
print("  Frontmatter проблемы:", fmiss or "нет ✓")
print("  Нестандартные callout:", sorted(set(badcallout)) or "нет ✓")

# E. Смешение кириллицы/латиницы внутри слова (гомоглифы/опечатки)
print("\n=== E. Смешение кириллица+латиница в слове ===")
mix=re.compile(r'[A-Za-z][а-яёА-ЯЁ]|[а-яёА-ЯЁ][A-Za-z]')
hits=[]
for p in mds:
    for i,line in enumerate(p.read_text(encoding='utf-8').splitlines(),1):
        for m in re.finditer(r'\S*(?:[A-Za-z][а-яёА-ЯЁ]|[а-яёА-ЯЁ][A-Za-z])\S*', line):
            w=m.group(0)
            # отфильтровать легитимные с дефисом (React-приложение) — там смешение через '-'
            if re.search(r'[A-Za-z][а-яёА-ЯЁ]|[а-яёА-ЯЁ][A-Za-z]', w.replace('-','')):
                hits.append(f"{rel(p)}:{i}  {w}")
# уникализируем по слову
seen=set(); uniq=[]
for h in hits:
    w=h.split('  ')[-1]
    if w not in seen: seen.add(w); uniq.append(h)
print("  " + ("\n  ".join(uniq) if uniq else "нет ✓"))

# F. Остатки старых имён/путей
print("\n=== F. Остатки старых имён ===")
old=['00 — Intern','01 — Junior','02 — Junior+','03 — Middle','Чеклист навыков',
 'Ресурсы и материалы','Проекты для портфолио','Маршрут.canvas','Ресурсы/Ресурсы']
left=[]
for p in list(mds)+list(cvs):
    t=p.read_text(encoding='utf-8')
    for tok in old:
        if tok in t: left.append(f"{rel(p)}: {tok!r}")
print("  " + ("\n  ".join(left) if left else "нет ✓"))

# G. Canvas
print("\n=== G. Canvas ===")
disk={p.as_posix() for p in root.rglob('*') if p.is_file()}
for c in cvs:
    d=json.loads(c.read_text(encoding='utf-8'))
    nodes,edges=d.get('nodes',[]),d.get('edges',[])
    ids=[n['id'] for n in nodes]
    dup=[x for x in set(ids) if ids.count(x)>1]
    miss=[n['file'] for n in nodes if n.get('type')=='file' and n['file'] not in disk]
    bade=[e['id'] for e in edges if e['fromNode'] not in ids or e['toNode'] not in ids]
    print(f"  {rel(c)}: узлов {len(nodes)} связей {len(edges)} | дубль-id: {dup or 'нет'} | нет файла: {miss or 'нет'} | битых связей: {bade or 'нет'}")

# H. Первый H1 vs имя файла
print("\n=== H. Первый H1 каждого файла (для сверки с именем) ===")
for p in mds:
    t=p.read_text(encoding='utf-8')
    m=re.search(r'^#\s+(.+)$', t, re.M)
    print(f"  {p.stem:38s} | H1: {m.group(1) if m else '— НЕТ H1 —'}")
PY

